SELECT COUNT(*)
  FROM collaboration_friendship
 WHERE user_id = #{userId}
   AND friend_user_id = #{friendUserId}

SELECT *
  FROM collaboration_friend_request
 WHERE id = #{id}

SELECT id
  FROM collaboration_conversation
 WHERE type = 'DIRECT'
   AND user_low_id = #{userLowId}
   AND user_high_id = #{userHighId}
 LIMIT 1

SELECT *
  FROM collaboration_conversation
 WHERE id = #{id}

SELECT COUNT(*)
  FROM collaboration_conversation_invite
 WHERE conversation_id = #{conversationId}
   AND invitee_id = #{inviteeId}
   AND status = 'PENDING'

mapper.update:
UPDATE collaboration_conversation_invite
   SET status = 'ACCEPTED',
       responded_at = NOW()
 WHERE conversation_id = #{conversationId}
   AND invitee_id = #{inviteeId}
   AND status = 'PENDING'

mapper.select:
SELECT COUNT(*)
  FROM collaboration_conversation_member
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}
   AND status = 'ACTIVE'

mapper.update:
UPDATE collaboration_conversation_member
   SET muted = #{muted}
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}

UPDATE collaboration_conversation
   SET updated_at = NOW()
 WHERE id = #{conversationId}

UPDATE collaboration_conversation_member
   SET last_read_message_id = GREATEST(COALESCE(last_read_message_id, 0), #{messageId}),
       last_read_at = NOW()
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}
   AND status = 'ACTIVE'

mapper.select:
SELECT last_seen_at
  FROM user_desktop_presence
 WHERE user_id = #{userId}

SELECT role
  FROM collaboration_conversation_member
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}
   AND status = 'ACTIVE'

mapper.update:
UPDATE collaboration_conversation
title = #{title}, description = #{description}, notice = #{notice}, type = #{type}, max_members = #{maxMembers}, invite_policy = #{invitePolicy}, allow_anonymous = #{allowAnonymous}, anonymous_only = #{anonymousOnly},
WHERE id = #{id}

UPDATE collaboration_conversation
   SET image_file_id = #{imageFileId}
 WHERE id = #{conversationId}

UPDATE collaboration_conversation
   SET password_hash = #{passwordHash}
 WHERE id = #{conversationId}

UPDATE collaboration_conversation_member
   SET role = #{role}
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}

UPDATE collaboration_conversation_member
   SET status = #{status},
       left_at = CASE WHEN #{status} = 'ACTIVE' THEN NULL ELSE NOW() END
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}

