SELECT COUNT(*)
  FROM collaboration_conversation_ban
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}
   AND deleted_at IS NULL

mapper.update:
UPDATE collaboration_conversation_ban
   SET deleted_at = COALESCE(deleted_at, NOW())
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}
   AND deleted_at IS NULL

mapper.select:
SELECT COUNT(*)
  FROM collaboration_conversation_invite_allow
 WHERE conversation_id = #{conversationId}
   AND user_id = #{userId}

SELECT c.id, c.type, c.title, c.description, c.image_file_id, c.notice, CASE WHEN c.type = 'PRIVATE' OR c.password_hash IS NOT NULL THEN 1 ELSE 0 END AS locked, ( SELECT COUNT(*) FROM collaboration_conversation_member cm WHERE cm.conversation_id = c.id AND cm.status = 'ACTIVE' ) AS member_count, c.updated_at FROM collaboration_conversation c WHERE c.type IN ('GROUP', 'PUBLIC', 'PRIVATE')
AND ( LOWER(COALESCE(c.title, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(COALESCE(c.description, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%') )
ORDER BY c.updated_at DESC, c.id DESC LIMIT #{limit}
